insert into public.kudos (id,sender_id,receiver_id,content,category,tags,images,created_at) values
('00000000-0000-4000-8000-000000001001','00000000-0000-4000-8000-000000000014','00000000-0000-4000-8000-000000000009','Cảm ơn vì những đêm thức khuya cùng nhau fix bug. Bạn là một đồng đội tuyệt vời mà ai cũng muốn được làm việc cùng.','LAN TỎA NĂNG LƯỢNG',ARRAY['#Positive','#Reliable','#Helpful','#Inspiring']::text[],ARRAY[]::text[],'2025-10-04T18:29:00.000Z'),
('00000000-0000-4000-8000-000000001002','00000000-0000-4000-8000-000000000010','00000000-0000-4000-8000-000000000025','Nhờ bạn review kỹ từng dòng code mà chất lượng sản phẩm được nâng lên rất nhiều. Cảm ơn người đồng đội tuyệt vời!','TẬN TÂM VỚI NGHỀ',ARRAY['#Proactive','#Teamwork','#Passionate','#Creative','#Leadership']::text[],ARRAY[]::text[],'2025-10-30T07:55:00.000Z'),
('00000000-0000-4000-8000-000000001003','00000000-0000-4000-8000-000000000006','00000000-0000-4000-8000-000000000010','Cảm ơn vì những đêm thức khuya cùng nhau fix bug. Bạn là một đồng đội tuyệt vời mà ai cũng muốn được làm việc cùng.','TINH THẦN ĐỒNG ĐỘI',ARRAY['#Proactive','#Teamwork','#Creative','#Innovative','#Inspiring']::text[],ARRAY['https://picsum.photos/seed/k3_0/400/400','https://picsum.photos/seed/k3_1/400/400','https://picsum.photos/seed/k3_2/400/400']::text[],'2025-10-02T05:54:00.000Z'),
('00000000-0000-4000-8000-000000001004','00000000-0000-4000-8000-000000000025','00000000-0000-4000-8000-000000000010','Cảm ơn vì những đêm thức khuya cùng nhau fix bug. Bạn là một đồng đội tuyệt vời mà ai cũng muốn được làm việc cùng.','LAN TỎA NĂNG LƯỢNG',ARRAY['#Positive','#Teamwork']::text[],ARRAY['https://picsum.photos/seed/k4_0/400/400','https://picsum.photos/seed/k4_1/400/400','https://picsum.photos/seed/k4_2/400/400','https://picsum.photos/seed/k4_3/400/400']::text[],'2025-10-06T13:26:00.000Z'),
('00000000-0000-4000-8000-000000001005','00000000-0000-4000-8000-000000000030','00000000-0000-4000-8000-000000000040','Cảm ơn vì luôn là người lắng nghe và đưa ra lời khuyên chân thành. Bạn xứng đáng nhận được điều tốt đẹp nhất.','LAN TỎA NĂNG LƯỢNG',ARRAY['#Reliable','#Inspiring','#Creative','#Dedicated']::text[],ARRAY['https://picsum.photos/seed/k5_0/400/400','https://picsum.photos/seed/k5_1/400/400','https://picsum.photos/seed/k5_2/400/400','https://picsum.photos/seed/k5_3/400/400','https://picsum.photos/seed/k5_4/400/400']::text[],'2025-10-09T13:49:00.000Z'),
('00000000-0000-4000-8000-000000001006','00000000-0000-4000-8000-000000000041','00000000-0000-4000-8000-000000000014','Cảm ơn bạn đã kiên nhẫn hướng dẫn mình từ những ngày đầu. Mình học được rất nhiều từ bạn.','TẬN TÂM VỚI NGHỀ',ARRAY['#Teamwork','#Positive','#Innovative','#Inspiring','#Creative']::text[],ARRAY['https://picsum.photos/seed/k6_0/400/400']::text[],'2025-10-16T20:15:00.000Z'),
('00000000-0000-4000-8000-000000001007','00000000-0000-4000-8000-000000000012','00000000-0000-4000-8000-000000000040','Cảm ơn vì luôn là người lắng nghe và đưa ra lời khuyên chân thành. Bạn xứng đáng nhận được điều tốt đẹp nhất.','LAN TỎA NĂNG LƯỢNG',ARRAY['#Positive','#Inspiring','#Supportive','#Reliable','#Proactive']::text[],ARRAY[]::text[],'2025-10-11T13:34:00.000Z'),
('00000000-0000-4000-8000-000000001008','00000000-0000-4000-8000-000000000001','00000000-0000-4000-8000-000000000041','Bạn đã chủ động nhận phần việc khó nhất về mình. Cảm ơn vì tinh thần dấn thân không ngại gian khó.','TINH THẦN ĐỒNG ĐỘI',ARRAY['#Creative','#Dedicated','#Proactive']::text[],ARRAY[]::text[],'2025-10-30T09:02:00.000Z'),
('00000000-0000-4000-8000-000000001009','00000000-0000-4000-8000-000000000021','00000000-0000-4000-8000-000000000005','Cảm ơn vì đã tin tưởng và trao cho mình cơ hội. Mình sẽ cố gắng để không phụ lòng bạn.','IDOL GIỚI TRẺ',ARRAY['#Helpful']::text[],ARRAY[]::text[],'2025-10-08T11:03:00.000Z'),
('00000000-0000-4000-8000-000000001010','00000000-0000-4000-8000-000000000018','00000000-0000-4000-8000-000000000014','Cảm ơn bạn vì nụ cười và năng lượng tích cực mang đến văn phòng mỗi sáng. Bạn làm mọi thứ tươi sáng hơn!','TẬN TÂM VỚI NGHỀ',ARRAY['#Positive']::text[],ARRAY['https://picsum.photos/seed/k10_0/400/400']::text[],'2025-10-21T13:48:00.000Z'),
